gYx(){return"\u067e\u06d5\u06cc\u0648\u06d5\u0646\u062f\u06cc \u0626\u06cc\u0646\u062a\u06d5\u0631\u0646\u06ce\u062a\u06d5\u06a9\u06d5\u062a \u0628\u067e\u0634\u06a9\u0646\u06d5 \u0648 \u062f\u0648\u0648\u0628\u0627\u0631\u06d5 \u0647\u06d5\u0648\u06b5 \u0628\u062f\u06d5\u0631\u06d5\u0648\u06d5."},
ga0I(){return"\u062f\u0648\u0648\u0628\u0627\u0631\u06d5 \u0647\u06d5\u0648\u06b5 \u0628\u062f\u06d5\u0631\u06d5\u0648\u06d5"},
